#include<bits/stdc++.h>
using namespace std;
long long dp[110][110];
const long long mod=998244353;
long long fastpow(long long x,long long y)
{
    long long ans=1;
    while(y)
    {
        if(y%2==1)
        {
            ans=ans*x%mod;
        }
        x=x*x%mod;
        y/=2;
    }
    return ans;
}
int main()
{
    int n,a,b,p,q;
    scanf("%d%d%d%d%d",&n,&a,&b,&p,&q);
    dp[a][b]=1;
    for(int i=0;i<n;i++)
    {
        for(int j=0;j<n;j++)
        {
            for(int k=1;k<=p;k++)
            {
                for(int l=1;l<=q;l++)
                {
                    dp[min(n,i+k)][min(n,j+l)]+=dp[i][j]*fastpow(p,mod-2)%mod*fastpow(q,mod-2)%mod;
                    dp[min(n,i+k)][min(n,j+l)]%=mod;
                }
            }
        }
    }
    long long ans=0;
    for(int i=1;i<=n;i++)
    {
        ans+=dp[n][i];
        ans%=mod;
    }
    printf("%lld",ans);
    return 0;
}
